/bin/bash -lc "cat <<'PY' >/tmp/clean_events.py
import csv
from datetime import datetime
from pathlib import Path

INPUT_DIR = Path(\"/data/csv\")
OUTPUT_FILE = Path(\"/tmp/clean_events.csv\")
EXPECTED_HEADERS = [\"event_id\", \"event_ts\", \"user_id\", \"event_type\", \"value\"]
HEADER_VARIANTS = {
    tuple(EXPECTED_HEADERS): EXPECTED_HEADERS,
    tuple(EXPECTED_HEADERS + [\"\"]): EXPECTED_HEADERS,
}


def normalize_timestamp(raw_ts: str) -> str:
    raw = raw_ts.strip()
    if not raw:
        raise ValueError(\"Missing timestamp\")
    if \"/\" in raw:
        parsed = datetime.strptime(raw, \"%d/%m/%Y\")
    else:
        parsed = datetime.strptime(raw.replace(\"T\", \" \").replace(\"Z\", \"\"), \"%Y-%m-%d %H:%M:%S\")
    return parsed.strftime(\"%Y-%m-%d %H:%M:%S\")


def normalize_value(raw_value: str) -> str:
    raw = raw.strip()
    if raw in {\"\", \"N/A\", \"null\", \"NULL\"}:
        return \"\\\\N\"
    return raw


def normalize_row(row: list[str]) -> dict[str, str]:
    padded = row + [\"\"] * (len(EXPECTED_HEADERS) - len(row))
    trimmed = padded[: len(EXPECTED_HEADERS)]
    normalized = dict(zip(EXPECTED_HEADERS, trimmed))
    normalized[\"event_ts\"] = normalize_timestamp(normalized[\"event_ts\"])
    normalized[\"value\"] = normalize_value(normalized[\"value\"])
    return normalized


def is_duplicate_header(row: list[str]) -> bool:
    return tuple([cell.strip() for cell in row if cell.strip()]) == tuple(EXPECTED_HEADERS)


def main() -> None:
    files = sorted(INPUT_DIR.glob(\"events_*.csv\"))
    seen = set()
    with OUTPUT_FILE.open(\"w\", newline=\"\") as out:
        writer = csv.DictWriter(out, fieldnames=EXPECTED_HEADERS)
        writer.writeheader()
        for path in files:
            with path.open(\"r\", newline=\"\") as inp:
                reader = csv.reader(inp)
                for row in reader:
                    if not row:
                        continue
                    if is_duplicate_header(row):
                        continue
                    row = [cell.strip() for cell in row]
                    if not row[0]:
                        continue
                    normalized = normalize_row(row)
                    if normalized[\"event_id\"] in seen:
                        continue
                    seen.add(normalized[\"event_id\"])
                    writer.writerow(normalized)


if __name__ == \"__main__\":
    main()
PY"

